65: func downloadDB(appVersion, cacheDir string, quiet, skipUpdate bool) error {
66: 	client := db.NewClient(cacheDir, quiet, false)
67: 	ctx := context.Background()
68: 	needsUpdate, err := client.NeedsUpdate(appVersion, skipUpdate)
69: 	if err != nil {
70: 		return xerrors.Errorf("database error: %w", err)
71: 	}
72: 
73: 	if needsUpdate {
74: 		logging.Log.Info("Need to update DB")
75: 		logging.Log.Info("Downloading DB...")
76: 		if err := client.Download(ctx, cacheDir); err != nil {
77: 			return xerrors.Errorf("failed to download vulnerability DB: %w", err)
78: 		}
79: 	}
80: 
81: 	// for debug
82: 	if err := showDBInfo(cacheDir); err != nil {
83: 		return xerrors.Errorf("failed to show database info: %w", err)
84: 	}
85: 	return nil
86: }
87: 
88: func showDBInfo(cacheDir string) error {
89: 	m := metadata.NewClient(cacheDir)
90: 	meta, err := m.Get()
91: 	if err != nil {
92: 		return xerrors.Errorf("something wrong with DB: %w", err)
93: 	}
94: 	log.Logger.Debugf("DB Schema: %d, UpdatedAt: %s, NextUpdate: %s, DownloadedAt: %s",
95: 		meta.Version, meta.UpdatedAt, meta.NextUpdate, meta.DownloadedAt)
96: 	return nil
97: }
