{"content":"1: package models
2: 
3: import (
4: 	"path/filepath"
5: 
6: 	"github.com/aquasecurity/trivy-db/pkg/db"
7: 	trivyDBTypes "github.com/aquasecurity/trivy-db/pkg/types"
8: 	"github.com/aquasecurity/trivy/pkg/detector/library"
9: 	ftypes "github.com/aquasecurity/trivy/pkg/fanal/types"
10: 	"github.com/aquasecurity/trivy/pkg/types"
11: 	"golang.org/x/xerrors"
12: 
13: 	"github.com/future-architect/vuls/logging"
14: )
15: 
16: // LibraryScanners is an array of LibraryScanner
17: type LibraryScanners []LibraryScanner
18: 
19: // Find : find by name
20: func (lss LibraryScanners) Find(path, name string) map[string]Library {
21: 	filtered := map[string]Library{}
22: 	for _, ls := range lss {
23: 		for _, lib := range ls.Libs {
24: 			if ls.LockfilePath == path && lib.Name == name {
25: 				filtered[ls.LockfilePath] = lib
26: 				break
27: 			}
28: 		}
29: 	}
30: 	return filtered
31: }
32: 
33: // Total returns total count of pkgs
34: func (lss LibraryScanners) Total() (total int) {
35: 	for _, lib := range lss {
36: 		total += len(lib.Libs)
37: 	}
38: 	return
39: }
40: 
41: // LibraryScanner has libraries information
42: type LibraryScanner struct {
43: 	Type string
44: 	Libs []Library
45: 
46: 	// The path to the Lockfile is stored.
47: 	LockfilePath string `json:"path,omitempty"`
48: }
49: 
50: // Library holds the attribute of a package library
51: type Library struct {
52: 	Name    string
53: 	Version string
54: 
55: 	// The Path to the library in the container image. Empty string when Lockfile scan.
56: 	// This field is used to convert the result JSON of a `trivy image` using trivy-to-vuls.
57: 	FilePath string
58: }
59: 
60: // Scan : scan target library
61: func (s LibraryScanner) Scan() ([]VulnInfo, error) {
62: 	scanner, err := library.NewDriver(s.Type)
63: 	if err != nil {
64: 		return nil, xerrors.Errorf("Failed to new a library driver %s: %w", s.Type, err)
65: 	}
66: 	var vulnerabilities = []VulnInfo{}
67: 	for _, pkg := range s.Libs {
68: 		tvulns, err := scanner.DetectVulnerabilities("", pkg.Name, pkg.Version)
69: 		if err != nil {
70: 			return nil, xerrors.Errorf("failed to detect %s vulnerabilities: %w", scanner.Type(), err)
71: 		}
72: 		if len(tvulns) == 0 {
73: 			continue
74: 		}
75: 
76: 		vulns := s.convertFanalToVuln(tvulns)
77: 		vulnerabilities = append(vulnerabilities, vulns...)
78: 	}
79: 
80: 	return vulnerabilities, nil
81: }
82: 
83: func (s LibraryScanner) convertFanalToVuln(tvulns []types.DetectedVulnerability) (vulns []VulnInfo) {
84: 	for _, tvuln := range tvulns {
85: 		vinfo, err := s.getVulnDetail(tvuln)
86: 		if err != nil {
87: 			logging.Log.Debugf("failed to getVulnDetail. err: %+v, tvuln: %#v", err, tvuln)
88: 			continue
89: 		}
90: 		vulns = append(vulns, vinfo)
91: 	}
92: 	return vulns
93: }
94: 
95: func (s LibraryScanner) getVulnDetail(tvuln types.DetectedVulnerability) (vinfo VulnInfo, err error) {
96: 	vul, err := db.Config{}.GetVulnerability(tvuln.VulnerabilityID)
97: 	if err != nil {
98: 		return vinfo, err
99: 	}
100: 
101: 	vinfo.CveID = tvuln.VulnerabilityID
102: 	vinfo.CveContents = getCveContents(tvuln.VulnerabilityID, vul)
103: 	vinfo.LibraryFixedIns = []LibraryFixedIn{
104: 		{
105: 			Key:     s.GetLibraryKey(),
106: 			Name:    tvuln.PkgName,
107: 			FixedIn: tvuln.FixedVersion,
108: 			Path:    s.LockfilePath,
109: 		},
110: 	}
111: 	return vinfo, nil
112: }
113: 
114: func getCveContents(cveID string, vul trivyDBTypes.Vulnerability) (contents map[CveContentType][]CveContent) {
115: 	contents = map[CveContentType][]CveContent{}
116: 	refs := []Reference{}
117: 	for _, refURL := range vul.References {
118: 		refs = append(refs, Reference{Source: "trivy", Link: refURL})
119: 	}
120: 
121: 	contents[Trivy] = []CveContent{
122: 		{
123: 			Type:          Trivy,
124: 			CveID:         cveID,
125: 			Title:         vul.Title,
126: 			Summary:       vul.Description,
127: 			Cvss3Severity: string(vul.Severity),
128: 			References:    refs,
129: 		},
130: 	}
131: 	return contents
132: }
133: 
134: // LibraryMap is filename and library type
135: var LibraryMap = map[string]string{
136: 	ftypes.NpmPkgLock:      "node",
137: 	ftypes.YarnLock:        "node",
138: 	ftypes.GemfileLock:     "ruby",
139: 	ftypes.CargoLock:       "rust",
140: 	ftypes.ComposerLock:    "php",
141: 	ftypes.PipRequirements: "python",
142: 	ftypes.PipfileLock:     "python",
143: 	ftypes.PoetryLock:      "python",
144: 	ftypes.NuGetPkgsLock:   ".net",
145: 	ftypes.NuGetPkgsConfig: ".net",
146: 	ftypes.GoMod:           "gomod",
147: 	ftypes.GoSum:           "gomod",
148: 	ftypes.MavenPom:        "java",
149: 	"*.jar":                "java",
150: 	"*.war":                "java",
151: 	"*.ear":                "java",
152: 	"*.par":                "java",
153: }
154: 
155: // GetLibraryKey returns target library key
156: func (s LibraryScanner) GetLibraryKey() string {
157: 	switch s.Type {
158: 	case ftypes.Bundler, ftypes.GemSpec:
159: 		return "ruby"
160: 	case ftypes.Cargo:
161: 		return "rust"
162: 	case ftypes.Composer:
163: 		return "php"
164: 	case ftypes.GoBinary, ftypes.GoModule:
165: 		return "gomod"
166: 	case ftypes.Jar, ftypes.Pom:
167: 		return "java"
168: 	case ftypes.Npm, ftypes.Yarn, ftypes.NodePkg, ftypes.JavaScript:
169: 		return "node"
170: 	case ftypes.NuGet:
171: 		return ".net"
172: 	case ftypes.Pipenv, ftypes.Poetry, ftypes.Pip, ftypes.PythonPkg:
173: 		return "python"
174: 	default:
175: 		filename := filepath.Base(s.LockfilePath)
176: 		switch filepath.Ext(filename) {
177: 		case ".jar", ".war", ".ear", ".par":
178: 			return "java"
179: 		default:
180: 			return LibraryMap[filename]
181: 		}
182: 	}
183: }
