185: // LibraryFixedIn has library fixed information
186: type LibraryFixedIn struct {
187: 	Key     string `json:"key,omitempty"`
188: 	Name    string `json:"name,omitempty"`
189: 	FixedIn string `json:"fixedIn,omitempty"`
190: 	Path    string `json:"path,omitempty"`
191: }
