114: func getCTIsViaHTTP(cveIDs []string, urlPrefix string) (responses []ctiResponse, err error) {
115: 	nReq := len(cveIDs)
116: 	reqChan := make(chan ctiRequest, nReq)
117: 	resChan := make(chan ctiResponse, nReq)
118: 	errChan := make(chan error, nReq)
119: 	defer close(reqChan)
120: 	defer close(resChan)
121: 	defer close(errChan)
122: 
123: 	go func() {
124: 		for _, cveID := range cveIDs {
125: 			reqChan <- ctiRequest{
126: 				cveID: cveID,
127: 			}
128: 		}
129: 	}()
130: 
131: 	concurrency := 10
132: 	tasks := util.GenWorkers(concurrency)
133: 	for i := 0; i < nReq; i++ {
134: 		tasks <- func() {
135: 			req := <-reqChan
136: 			url, err := util.URLPathJoin(
137: 				urlPrefix,
138: 				req.cveID,
139: 			)
140: 			if err != nil {
141: 				errChan <- err
142: 			} else {
143: 				logging.Log.Debugf("HTTP Request to %s", url)
144: 				httpGetCTI(url, req, resChan, errChan)
145: 			}
146: 		}
147: 	}
148: 
149: 	timeout := time.After(2 * 60 * time.Second)
150: 	var errs []error
151: 	for i := 0; i < nReq; i++ {
152: 		select {
153: 		case res := <-resChan:
154: 			responses = append(responses, res)
155: 		case err := <-errChan:
156: 			errs = append(errs, err)
157: 		case <-timeout:
158: 			return nil, xerrors.New("Timeout Fetching CTI")
159: 		}
160: 	}
161: 	if len(errs) != 0 {
162: 		return nil, xerrors.Errorf("Failed to fetch CTI. err: %w", errs)
163: 	}
164: 	return
165: }
166: 
167: type ctiRequest struct {
168: 	cveID string
169: }
170: 
171: func httpGetCTI(url string, req ctiRequest, resChan chan<- ctiResponse, errChan chan<- error) {
172: 	var body string
173: 	var errs []error
174: 	var resp *http.Response
175: 	count, retryMax := 0, 3
176: 	f := func() (err error) {
177: 		//  resp, body, errs = gorequest.New().SetDebug(config.Conf.Debug).Get(url).End()
178: 		resp, body, errs = gorequest.New().Timeout(10 * time.Second).Get(url).End()
179: 		if 0 < len(errs) || resp == nil || resp.StatusCode != 200 {
180: 			count++
181: 			if count == retryMax {
182: 				return nil
183: 			}
184: 			return xerrors.Errorf("HTTP GET error, url: %s, resp: %v, err: %+v", url, resp, errs)
185: 		}
186: 		return nil
187: 	}
188: 	notify := func(err error, t time.Duration) {
189: 		logging.Log.Warnf("Failed to HTTP GET. retrying in %s seconds. err: %+v", t, err)
190: 	}
191: 	if err := backoff.RetryNotify(f, backoff.NewExponentialBackOff(), notify); err != nil {
192: 		errChan <- xerrors.Errorf("HTTP Error %w", err)
193: 		return
194: 	}
195: 	if count == retryMax {
196: 		errChan <- xerrors.New("Retry count exceeded")
197: 		return
198: 	}
199: 
200: 	resChan <- ctiResponse{
201: 		request: req,
202: 		json:    body,
203: 	}
204: }
