206: func newCTIDB(cnf config.VulnDictInterface) (ctidb.DB, error) {
207: 	if cnf.IsFetchViaHTTP() {
208: 		return nil, nil
209: 	}
210: 	path := cnf.GetURL()
211: 	if cnf.GetType() == "sqlite3" {
212: 		path = cnf.GetSQLite3Path()
213: 	}
214: 	driver, locked, err := ctidb.NewDB(cnf.GetType(), path, cnf.GetDebugSQL(), ctidb.Option{})
215: 	if err != nil {
216: 		if locked {
217: 			return nil, xerrors.Errorf("Failed to init cti DB. SQLite3: %s is locked. err: %w", cnf.GetSQLite3Path(), err)
218: 		}
219: 		return nil, xerrors.Errorf("Failed to init cti DB. DB Path: %s, err: %w", path, err)
220: 	}
221: 	return driver, nil
222: }
