// and names are properly converted to library scanner types. This tests
// the conversion logic that bridges Trivy's analysis with vuls' library scanning.
func TestLibraryTypeRecognitionFromFilename(t *testing.T) {
	tests := []struct {
		filename   string
		shouldFail bool
		description string
	}{
		{
			filename:   "pnpm.lock",
			shouldFail: true,
			description: "PNPM lockfile - should fail due to missing LibraryMap entry",
		},
		{
			filename:   "package-lock.json",
			shouldFail: false,
			description: "NPM lockfile - should be recognized",
		},
		{
			filename:   "yarn.lock",
			shouldFail: false,
			description: "Yarn lockfile - should be recognized",
		},
		{
			filename:   "packages.lock.json",
			shouldFail: true,
			description: ".NET lockfile - should fail if not in LibraryMap",
		},
		{
			filename:   "Gemfile.lock",
			shouldFail: false,
			description: "Ruby Gemfile - should be recognized",
		},
	}

	libraryMap := map[string]string{
		ftypes.NpmPkgLock:      "node",
		ftypes.YarnLock:        "node",
		ftypes.GemfileLock:     "ruby",
		ftypes.CargoLock:       "rust",
		ftypes.ComposerLock:    "php",
		ftypes.PipRequirements: "python",
		ftypes.PipfileLock:     "python",
		ftypes.PoetryLock:      "python",
		ftypes.NuGetPkgsLock:   ".net",
		ftypes.NuGetPkgsConfig: ".net",
		ftypes.GoMod:           "gomod",
		ftypes.GoSum:           "gomod",
		ftypes.MavenPom:        "java",
		"*.jar":                "java",
		"*.war":                "java",
		"*.ear":                "java",
		"*.par":                "java",
	}

	for _, tt := range tests {
		_, exists := libraryMap[tt.filename]

		if tt.shouldFail && exists {
			t.Errorf("Test case %q (%s): Expected to fail (not in map) but found entry",
				tt.filename, tt.description)
		} else if !tt.shouldFail && !exists {
			t.Errorf("Test case %q (%s): Expected to succeed (be in map) but was not found",
				tt.filename, tt.description)
		}
	}
}

