// Helper function to check if a value is in a slice
func contains(slice []string, item string) bool {
	for _, v := range slice {
		if v == item {
			return true
		}
	}
	return false
}

// Helper function to compare maps
func mapsEqual(m1, m2 map[string]string) bool {
	if len(m1) != len(m2) {
		return false
	}
	for k, v := range m1 {
		if val, exists := m2[k]; !exists || val != v {
			return false
		}
	}
	return true
}

// TestFileWriteForMocking writes test mock data for analysis
func testWriteMockData() ([]byte, error) {
	var buf bytes.Buffer
	buf.WriteString("{\n")
	buf.WriteString("  \"vulnerabilities\": [\n")
	buf.WriteString("    {\"id\": \"CVE-2021-1234\", \"package\": \"express\", \"version\": \"4.17.1\"}\n")
	buf.WriteString("  ]\n")
	buf.WriteString("}\n")
	return buf.Bytes(), nil
}

// TestMockDataGeneration ensures we can generate mock test data
func TestMockDataGeneration(t *testing.T) {
	data, err := testWriteMockData()
	if err != nil {
		t.Fatalf("Failed to generate mock data: %v", err)
	}
	if len(data) == 0 {
		t.Errorf("Generated mock data is empty")
	}

	// Verify it's valid JSON-like structure
	reader := bytes.NewReader(data)
	content := make([]byte, 1)
	n, err := reader.Read(content)
	if err != nil && err != io.EOF {
		t.Errorf("Failed to read mock data: %v", err)
	}
	if n > 0 {
		t.Logf("Mock data generated successfully: %d bytes", len(data))
	}
}

// TestPackageTypeReflection uses reflection to verify package structure
func TestPackageTypeReflection(t *testing.T) {
	// Define a mock package structure to verify what fields should exist
	type MockPackage struct {
		Name    string
		Version string
		Type    string
	}

	mockPkg := MockPackage{
		Name:    "express",
		Version: "4.17.1",
		Type:    "node",
	}

	pkgType := reflect.TypeOf(mockPkg)
	for i := 0; i < pkgType.NumField(); i++ {
		field := pkgType.Field(i)
		t.Logf("Expected package field: %s (type: %s)", field.Name, field.Type)
	}
}

