	for _, v := range slice {
		if v == item {
			return true
		}
	}
	return false
}

// Helper function to compare maps
func mapsEqual(m1, m2 map[string]string) bool {
	if len(m1) != len(m2) {
		return false
	}
	for k, v := range m1 {
		if val, exists := m2[k]; !exists || val != v {
			return false
		}
	}
	return true
}

