// TestLibraryTypeRecognitionFromFilename tests that lockfile extensions
// and names are properly converted to library scanner types. This tests
// the conversion logic that bridges Trivy's analysis with vuls' library scanning.
func TestLibraryTypeRecognitionFromFilename(t *testing.T) {
	tests := []struct {
		filename    string
		shouldExist bool
		description string
	}{
		{
			filename:    "pnpm.lock",
			shouldExist: false,
			description: "PNPM lockfile - NOT in LibraryMap (BUG)",
		},
		{
			filename:    "package-lock.json",
			shouldExist: true,
			description: "NPM lockfile - should be recognized",
		},
		{
			filename:    "yarn.lock",
			shouldExist: true,
			description: "Yarn lockfile - should be recognized",
		},
		{
			filename:    "packages.lock.json",
			shouldExist: true,
			description: ".NET lockfile - in LibraryMap",
		},
		{
			filename:    "Gemfile.lock",
			shouldExist: true,
			description: "Ruby Gemfile - should be recognized",
		},
	}

	libraryMap := map[string]string{
		"package-lock.json":    "node",
		"yarn.lock":            "node",
		"Gemfile.lock":         "ruby",
		"Cargo.lock":           "rust",
		"composer.lock":        "php",
		"requirements.txt":     "python",
		"Pipfile.lock":         "python",
		"poetry.lock":          "python",
		"packages.lock.json":   ".net",
		"packages.config.xml":  ".net",
		"go.mod":               "gomod",
		"go.sum":               "gomod",
		"pom.xml":              "java",
		"*.jar":                "java",
		"*.war":                "java",
		"*.ear":                "java",
		"*.par":                "java",
		// MISSING: "pnpm.lock" entry
	}

	for _, tt := range tests {
		_, exists := libraryMap[tt.filename]

		if tt.shouldExist && !exists {
			t.Errorf("BUG TEST: File %q (%s): Expected to be in LibraryMap but was not found",
				tt.filename, tt.description)
		} else if !tt.shouldExist && exists {
			t.Logf("File %q (%s): Correctly NOT in LibraryMap (or this is unexpected)",
				tt.filename, tt.description)
		}
	}
}

