	t.Run("AnalyzerScopeControl", TestLibraryScannerAnalyzerScope)
	t.Run("LibraryScanInitialization", TestLibraryScanWithoutProperInitialization)
	t.Run("ScanResultAccuracy", TestScanResultAccuracy)
}

