func TestLibraryScannerAnalyzerScope(t *testing.T) {
	// LOCATION: scanner/base.go:667-730, specifically the AnalyzeLibraries function
	//
	// PURPOSE: When scanning for library vulnerabilities (package managers like npm, pip, etc),
	// the code creates a Trivy analyzer with a disabled list to prevent:
