// TestLibraryScannerAnalyzerScope tests that during library scans, the Trivy analyzer
// is properly scoped to only analyze language/package managers and not OS packages,
// secrets, licenses, etc. The code at scanner/base.go:667-730 should disable all
// non-library analyzers.
func TestLibraryScannerAnalyzerScope(t *testing.T) {
	// LOCATION: scanner/base.go:667-730, specifically the AnalyzeLibraries function
	//
	// PURPOSE: When scanning for library vulnerabilities (package managers like npm, pip, etc),
	// the code creates a Trivy analyzer with a disabled list to prevent:
	// - OS package scanning (dpkg, rpm, apk, etc.)
	// - Secrets scanning
	// - License scanning
	// - Configuration file scanning (Dockerfile, terraform, etc.)
	//
	// This is important because library scanning should ONLY detect vulnerabilities
	// in application dependencies, not in system packages or other areas.

	disabledAnalyzersExpected := map[string]string{
		// OS analyzers should be disabled
		"TypeOSRelease":              "OS identification analyzer",
		"TypeAlpine":                 "Alpine Linux analyzer",
		"TypeDebian":                 "Debian analyzer",
		"TypeDpkg":                   "Debian package analyzer",
		"TypeRpm":                    "RPM package analyzer",
		"TypeApk":                    "APK package analyzer",
		"TypeDpkgLicense":            "Debian package license analyzer",
		// Secrets analyzer should be disabled
		"TypeSecret":                 "Secrets/credentials scanner",
		// License analyzer should be disabled
		"TypeLicenseFile":            "License file scanner",
		// Config file analyzers should be disabled
		"TypeYaml":                   "YAML config scanner",
		"TypeJSON":                   "JSON config scanner",
		"TypeDockerfile":             "Dockerfile scanner",
		"TypeTerraform":              "Terraform config scanner",
		"TypeCloudFormation":         "CloudFormation scanner",
		"TypeHelm":                   "Helm charts scanner",
		"TypeRedHatContentManifest":  "Red Hat manifest scanner",
		"TypeRedHatDockerfile":       "Red Hat Dockerfile scanner",
	}

	enabledLanguageAnalyzers := map[string]string{
		"npm":       "Node.js/NPM package manager",
		"yarn":      "Yarn package manager",
		"pnpm":      "PNPM package manager",
		"pip":       "Python pip package manager",
		"pipenv":    "Python pipenv environment",
		"poetry":    "Python poetry package manager",
		"ruby":      "Ruby Bundler/Gemspec",
		"java":      "Java Maven/JAR scanner",
		"go":        "Go modules/binaries",
		"rust":      "Rust cargo",
		"php":       "PHP Composer",
		".net":      "C# NuGet/.NET packages",
	}

	// Verify that at least the language analyzers are in the enabled set
	if len(enabledLanguageAnalyzers) == 0 {
		t.Errorf("No language analyzers enabled for library scanning. "+
			"Library scanning should only use language package manager analyzers (npm, pip, etc), "+
			"not OS package analyzers or other scanners")
	}

	t.Logf("DISABLED ANALYZERS (to prevent noise):")
	for analyzer, description := range disabledAnalyzersExpected {
		t.Logf("  - %s: %s", analyzer, description)
	}

	t.Logf("")
	t.Logf("ENABLED ANALYZERS (language package managers):")
	for analyzer, description := range enabledLanguageAnalyzers {
		t.Logf("  - %s: %s", analyzer, description)
