	// BUG CHECK: Verify that PNPM is in the enabled list
	// If it's not available as an analyzer option, library scanning for pnpm.lock will fail
	if _, hasConfig := enabledLanguageAnalyzers["pnpm"]; hasConfig {
		t.Logf("Note: PNPM is listed as a language analyzer but may not be properly registered " +
			"with Trivy, or pnpm.lock files may not be recognized by the LibraryMap.")
	}
}

